const evento = $input.first().json;
let telegramUserId = null;
let texto = null;
let callbackData = null;
let esFoto = false;
let esCallback = false;

if (evento.callback_query) {
  telegramUserId = String(evento.callback_query.from.id);
  callbackData = evento.callback_query.data;
  esCallback = true;
} else if (evento.message) {
  telegramUserId = String(evento.message.from.id);
  if (evento.message.photo) {
    esFoto = true;
  } else if (typeof evento.message.text === 'string') {
    texto = evento.message.text;
  }
}

const esRespuesta = esCallback || (texto !== null);
const respuesta = esCallback ? callbackData : texto;

return [{
  json: {
    telegram_user_id: telegramUserId,
    es_foto: esFoto,
    es_respuesta: esRespuesta,
    respuesta: respuesta,
  },
}];

// ENGANCHE C-11 (deshabilitado a proposito, D-6 del design): aqui se
// invocaria el pipeline OCR zonal cuando C-11 exista. Sin C-11 construido,
// este nodo permanece deshabilitado -- n8n bypassea la conexion y la rama
// foto degrada honestamente enviando 'OCR no disponible' (nodo siguiente),
// sin romper la sesion ni fingir un OCR que no existe.
return $input.all();

const fs = require('fs');
const crypto = require('crypto');
const contexto = $('Normalizar Evento de Telegram').first().json;
const subcomando = contexto.es_respuesta ? 'avanzar' : 'resolver';
const payload = subcomando === 'avanzar'
  ? { telegram_user_id: contexto.telegram_user_id, respuesta: contexto.respuesta }
  : { telegram_user_id: contexto.telegram_user_id };

const dirTemp = $env.PIPELINE_CARPETA_CORRIDAS + '/telegram_cli';
fs.mkdirSync(dirTemp, { recursive: true });
const idArchivo = crypto.randomBytes(8).toString('hex');
const archivoPayload = dirTemp + '/' + idArchivo + '.json';
fs.writeFileSync(archivoPayload, JSON.stringify(payload), 'utf-8');

return [{ json: { archivo_payload: archivoPayload, subcomando: subcomando } }];

// Recombina la salida JSON de 'pipeline.session_cli' (D-2, exit-0 siempre)
// con el contexto del evento normalizado -- mismo patron anti-divergencia
// que 'Interpretar Resultado' en ejecutar_etapa_con_reintentos.json (C-08):
// Execute Command no propaga el contexto de items anteriores.
const salida = $input.first().json;
const contexto = $('Normalizar Evento de Telegram').first().json;
let resultado;
try {
  resultado = JSON.parse(salida.stdout);
} catch (e) {
  resultado = { autorizado: false, mensaje: 'Fallo interno al interpretar la respuesta del sistema.' };
}
return [{
  json: {
    ...resultado,
    telegram_user_id: contexto.telegram_user_id,
  },
}];

const fs = require('fs');
const crypto = require('crypto');
const contexto = $('Parsear Resultado CLI').first().json;
const payload = { session_id: contexto.session_id };

const dirTemp = $env.PIPELINE_CARPETA_CORRIDAS + '/telegram_cli';
fs.mkdirSync(dirTemp, { recursive: true });
const idArchivo = crypto.randomBytes(8).toString('hex');
const archivoPayload = dirTemp + '/' + idArchivo + '.json';
fs.writeFileSync(archivoPayload, JSON.stringify(payload), 'utf-8');

return [{ json: { archivo_payload: archivoPayload, subcomando: 'finalizar_setup' } }];

const salida = $input.first().json;
const contexto = $('Normalizar Evento de Telegram').first().json;
let resultado;
try {
  resultado = JSON.parse(salida.stdout);
} catch (e) {
  resultado = { ok: false, error: 'Fallo interno al interpretar finalizar_setup.' };
}
return [{
  json: {
